{
  "plan": [
    {
      "step": 1,
      "tool": "jira.list_tickets",
      "arguments": {
        "project": "CURRENT_PROJECT",
        "filters": {
          "issue_type": ["Story", "Task", "Requirement"],
          "status": ["Open", "In Progress", "To Do"]
        },
        "fields": ["summary", "description", "priority", "assignee", "labels", "acceptance_criteria"],
        "max_results": 50
      },
      "depends_on": []
    },
    {
      "step": 2,
      "tool": "calendar.list_events",
      "arguments": {
        "calendar_id": "team-calendar",
        "time_min": "2025-01-27T08:00:00Z",
        "time_max": "2025-01-28T18:00:00Z",
        "attendees": ["team-all@company.com"],
        "show_deleted": false
      },
      "depends_on": []
    },
    {
      "step": 3,
      "tool": "iam.check_permission",
      "arguments": {
        "principal": "current_user",
        "resource": "calendar.create_event",
        "action": "write",
        "context": {
          "team": "cross-team",
          "scope": "standup_scheduling"
        }
      },
      "depends_on": [1, 2]
    },
    {
      "step": 4,
      "tool": "calendar.create_event",
      "arguments": {
        "title": "Cross-Team Project Standup",
        "description": "Daily standup to discuss project requirements and progress. Agenda based on Jira tickets: $1.results",
        "start_time": "2025-01-28T09:00:00Z",
        "end_time": "2025-01-28T09:30:00Z",
        "attendees": ["team-all@company.com"],
        "availability_check": "$2.results",
        "recurrence": "DAILY",
        "location": "Zoom/Virtual",
        "reminders": [
          {"method": "email", "minutes_before": 30},
          {"method": "popup", "minutes_before": 10}
        ]
      },
      "depends_on": [3]
    },
    {
      "step": 5,
      "tool": "audit.log_action",
      "arguments": {
        "action": "calendar.create_event",
        "actor": "current_user",
        "resource": "standup_meeting",
        "resource_id": "$4.event_id",
        "details": {
          "event_title": "Cross-Team Project Standup",
          "scheduled_time": "2025-01-28T09:00:00Z",
          "attendees": "team-all@company.com",
          "jira_tickets_referenced": "$1.total_results"
        },
        "status": "success",
        "timestamp": "2025-01-27T00:00:00Z"
      },
      "depends_on": [4]
    },
